import { GoldRushClient } from "@covalenthq/client-sdk";

const client = new GoldRushClient(process.env.GOLDRUSH_API_KEY);

async function getLiquidityMap(tokenAddress) {
  const chains = ["eth-mainnet", "matic-mainnet", "arbitrum-mainnet", "base-mainnet"];
  const results = await Promise.all(
    chains.map(chain =>
      client.BalanceService.getHistoricalTokenBalances(chain, tokenAddress)
    )
  );
  return results.map((r, i) => ({ chain: chains[i], data: r.data }));
}
